const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = BASE_PREMIUMS[step.items[0].type];
    const premium = Math.ceil(basePremium * 1.1) + 5;
    return { premium };
  });
  return { results };
}

