const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

function computeBasePremium(items: any[]): number {
  let total = 0;
  let componentCount = 0;

  for (const item of items) {
    const mainPremium = BASE_PREMIUMS[item.type];
    if (mainPremium !== undefined) {
      total += mainPremium;
    } else {
      componentCount++;
    }
  }

  const blocks = Math.floor(componentCount / COMPONENT_BLOCK_SIZE);
  const remainder = componentCount % COMPONENT_BLOCK_SIZE;
  total += blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;

  return total;
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const basePremium = computeBasePremium(step.items);
    const premium = Math.ceil(basePremium * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT) / 100) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

