const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
};

const COMPONENT_INSURANCE_VALUE = 250;
const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const CURSED_SURCHARGE_PERCENT = 50;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_PERCENT = -20;
const REPEAT_CONTRACT_DISCOUNT_PERCENT = -15;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

function adjustByPercent(amount: number, percent: number): number {
  return Math.ceil(amount * (100 + percent) / 100);
}

function isMainItem(item: any): boolean {
  return item.type in BASE_PREMIUMS;
}

function computeItemPremium(item: any): number {
  let premium = BASE_PREMIUMS[item.type];
  if (item.cursed) {
    premium = adjustByPercent(premium, CURSED_SURCHARGE_PERCENT);
  }
  if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
    premium = adjustByPercent(premium, HIGH_ENCHANTMENT_SURCHARGE_PERCENT);
  }
  return premium;
}

function computeBasePremium(items: any[]): number {
  const mainItemTotal = items
    .filter(isMainItem)
    .reduce((sum, item) => sum + computeItemPremium(item), 0);

  const componentCount = items.filter((item) => !isMainItem(item)).length;
  const blocks = Math.floor(componentCount / COMPONENT_BLOCK_SIZE);
  const remainder = componentCount % COMPONENT_BLOCK_SIZE;
  const componentTotal = blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;

  return mainItemTotal + componentTotal;
}

function computeInsuranceSum(items: any[]): number {
  return items.reduce((sum, item) => {
    const value = INSURANCE_VALUES[item.type] ?? COMPONENT_INSURANCE_VALUE;
    return sum + value;
  }, 0);
}

function processQuote(step: any, customer: any, quoteCount: number): { premium: number } {
  const basePremium = computeBasePremium(step.items);
  const contractPercent = quoteCount === 0
    ? FIRST_INSURANCE_SURCHARGE_PERCENT
    : REPEAT_CONTRACT_DISCOUNT_PERCENT;
  let premium = adjustByPercent(basePremium, contractPercent);
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
    premium = adjustByPercent(premium, LOYALTY_DISCOUNT_PERCENT);
  }
  premium += PROCESSING_FEE;
  return { premium };
}

function processClaim(step: any, policy: { remainingCap: number }): { payout: number; remainingCap: number } {
  const totalDamage = step.incident.damages.reduce(
    (sum: number, d: any) => sum + d.amount, 0
  );
  const payout = Math.min(Math.max(0, totalDamage - DEDUCTIBLE), policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

export function processScenario(scenario: any): any {
  const customer = scenario.customer;
  let quoteCount = 0;
  const policies: { items: any[]; remainingCap: number }[] = [];
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      const result = processQuote(step, customer, quoteCount);
      quoteCount++;
      const insuranceSum = computeInsuranceSum(step.items);
      policies.push({ items: step.items, remainingCap: insuranceSum * CAP_MULTIPLIER });
      return result;
    } else {
      return processClaim(step, policies[step.policy]);
    }
  });
  return { results };
}

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should compute premium for a single sword for a new customer (base + first insurance surcharge + processing fee)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should compute correct base premiums for each main item type (amulet, staff, potion)", () => {
      const makeScenario = (type: string) => ({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type, material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });

      expect(processScenario(makeScenario("amulet")).results[0]).toEqual({ premium: 71 });
      expect(processScenario(makeScenario("staff")).results[0]).toEqual({ premium: 93 });
      expect(processScenario(makeScenario("potion")).results[0]).toEqual({ premium: 49 });
    });
    it("should compute base premium for a single component", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should apply block discount for 3 alike components (60G instead of 3x25G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should sum premiums for multiple different items", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 181 });
    });
    it("should apply 50% cursed item surcharge", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 170 });
    });
    it("should apply 30% surcharge for highly enchanted items (enchantment >= 5)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 148 });
    });
    it("should apply 20% loyalty discount for long-standing customers (>= 2 years)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 93 });
    });
    it("should apply 15% repeat contract discount on second quote and omit first insurance surcharge", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 115 });
      expect(result.results[1]).toEqual({ premium: 90 });
    });
    it("should round amounts in MHPCO's favor (ceiling)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      // base 40, +10% first = ceil(44) = 44, -20% loyalty = ceil(35.2) = 36, +5 fee = 41
      expect(result.results[0]).toEqual({ premium: 41 });
    });
  });

  describe("Processing claims", () => {
    it("should apply 100G deductible per damage event", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "claim" as const,
            policy: 0,
            incident: {
              cause: "fire",
              damages: [{ itemType: "amulet", amount: 300 }],
            },
          },
        ],
      };

      const result = processScenario(scenario);

      expect(result.results[0]).toEqual({ premium: 71 });
      expect(result.results[1]).toEqual({ payout: 200, remainingCap: 1000 });
    });
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to dragon material items");
  });
});

